from collections import deque

graph = {'A':['B','C'],'B':['D'],'C':['E'],'D':[],'E':[]}
frontier = deque([('A',['A'])])
visited = set()
while frontier:
    node, path = frontier.popleft()
    if node in visited:
        continue
    visited.add(node)
    if node == 'E':
        print(path)
        break
    for nxt in graph[node]:
        frontier.append((nxt, path + [nxt]))

